def add_dependency(self, task_name, dependency_name):
        if task_name in self.task_dependencies:
            self.task_dependencies[task_name].append(dependency_name)
        else:
            self.task_dependencies[task_name] = [dependency_name]

def can_complete_task(self, task_name):
        if task_name not in self.task_dependencies:
            return True
        for dependency in self.task_dependencies[task_name]:
            if not any(task.name == dependency and task.status == 'completed' for task in self.tasks):
                return False
        return True
